// Código para n8n v1.112.6 - Analizador de Tokens (Versión Limpia)

const executionData = $input.all()[0].json;

let totalTokensEntrada = 0;
let totalTokensSalida = 0;

// Función auxiliar para buscar tokens recursivamente
function buscarTokensRecursivo(obj) {
  let entrada = 0;
  let salida = 0;

  if (typeof obj !== 'object' || obj === null) {
    return { entrada, salida };
  }

  Object.keys(obj).forEach(key => {
    const value = obj[key];

    // Buscar por nombres de propiedades específicas
    if (typeof value === 'number') {
      if (key.includes('promptTokens') || key.includes('prompt_tokens') || key.includes('inputTokens')) {
        entrada += value;
      } else if (key.includes('completionTokens') || key.includes('completion_tokens') || key.includes('outputTokens')) {
        salida += value;
      }
    }

    // Recursión para objetos anidados
    if (typeof value === 'object' && value !== null && !Array.isArray(value)) {
      const recursiveResult = buscarTokensRecursivo(value);
      entrada += recursiveResult.entrada;
      salida += recursiveResult.salida;
    }
  });

  return { entrada, salida };
}

try {
  const runData = executionData.data?.resultData?.runData || {};

  // Recorrer todos los nodos ejecutados
  Object.keys(runData).forEach(nodeName => {
    const nodeExecutions = runData[nodeName];

    if (Array.isArray(nodeExecutions)) {
      nodeExecutions.forEach(execution => {

        // Buscar en data.main
        if (execution.data?.main) {
          execution.data.main.forEach(outputArray => {
            if (Array.isArray(outputArray)) {
              outputArray.forEach(item => {
                if (item.json) {

                  // PATRÓN 1: tokenUsage directo
                  if (item.json.tokenUsage) {
                    const tokenUsage = item.json.tokenUsage;
                    totalTokensEntrada += tokenUsage.promptTokens || 0;
                    totalTokensSalida += tokenUsage.completionTokens || 0;
                  }

                  // PATRÓN 2: response.usage
                  if (item.json.response?.usage) {
                    const usage = item.json.response.usage;
                    totalTokensEntrada += usage.prompt_tokens || 0;
                    totalTokensSalida += usage.completion_tokens || 0;
                  }

                  // PATRÓN 3: llmOutput.tokenUsage
                  if (item.json.llmOutput?.tokenUsage) {
                    const tokenUsage = item.json.llmOutput.tokenUsage;
                    totalTokensEntrada += tokenUsage.promptTokens || 0;
                    totalTokensSalida += tokenUsage.completionTokens || 0;
                  }

                  // PATRÓN 4: metadata
                  if (item.json.metadata?.tokenUsage) {
                    const tokenUsage = item.json.metadata.tokenUsage;
                    totalTokensEntrada += tokenUsage.promptTokens || tokenUsage.inputTokens || 0;
                    totalTokensSalida += tokenUsage.completionTokens || tokenUsage.outputTokens || 0;
                  }

                  // PATRÓN 5: Buscar recursivamente
                  const recursiveTokens = buscarTokensRecursivo(item.json);
                  totalTokensEntrada += recursiveTokens.entrada;
                  totalTokensSalida += recursiveTokens.salida;
                }
              });
            }
          });
        }

        // Buscar en ai_languageModel
        if (execution.data?.ai_languageModel) {
          execution.data.ai_languageModel.forEach(outputArray => {
            if (Array.isArray(outputArray)) {
              outputArray.forEach(item => {
                if (item.json?.tokenUsage) {
                  const tokenUsage = item.json.tokenUsage;
                  totalTokensEntrada += tokenUsage.promptTokens || 0;
                  totalTokensSalida += tokenUsage.completionTokens || 0;
                }
              });
            }
          });
        }
      });
    }
  });

  // Resultado final
  const tokensTotal = totalTokensEntrada + totalTokensSalida;

  return [{
    json: {
      "TotalTokensEntrada": totalTokensEntrada,
      "TotalTokensSalida": totalTokensSalida,
      "TokensTotales": tokensTotal
    }
  }];

} catch (error) {
  return [{
    json: {
      "TotalTokensEntrada": 0,
      "TotalTokensSalida": 0,
      "TokensTotales": 0,
      "error": error.message
    }
  }];
}
